9	// FormatSessionLogLines formats ddx-agent JSONL log entries into readable progress.
10	// It is used by both the CLI (local execute-loop) and the server worker log endpoint.
11	func FormatSessionLogLines(lines []string) string {
12		var sb strings.Builder
13		for _, line := range lines {
14			line = strings.TrimSpace(line)
15			if line == "" {
16				continue
17			}
18			var entry map[string]any
19			if err := json.Unmarshal([]byte(line), &entry); err != nil {
20				continue
21			}
22			entryType, _ := entry["type"].(string)
23			switch entryType {
24			case "session.start":
25				model, _ := entry["data"].(map[string]any)["model"].(string)
26				fmt.Fprintf(&sb, "▶ session started (model: %s)\n", model)
27			case "llm.request":
28				data, _ := entry["data"].(map[string]any)
29				attemptIdx, _ := data["attempt_index"].(float64)
30				// Extract a hint from the last user message in the conversation.
31				promptHint := ""
32				if msgs, ok := data["messages"].([]any); ok {
33					for i := len(msgs) - 1; i >= 0; i-- {
34						if msg, ok := msgs[i].(map[string]any); ok {
35							if role, _ := msg["role"].(string); role == "user" {
36								if content, _ := msg["content"].(string); content != "" {
37									promptHint = " [" + truncateStr(strings.TrimSpace(content), 60) + "]"
38								}
39								break
40							}
41						}
42					}
43				}
44				fmt.Fprintf(&sb, "  → llm request (attempt %.0f)%s\n", attemptIdx, promptHint)
45			case "llm.response":
46				data, _ := entry["data"].(map[string]any)
47				model, _ := data["model"].(string)
48				latency, _ := data["latency_ms"].(float64)
49				// Tokens: data.attempt.cost.raw.total_tokens
50				var tokens float64
51				if attempt, ok := data["attempt"].(map[string]any); ok {
52					if cost, ok := attempt["cost"].(map[string]any); ok {
53						if raw, ok := cost["raw"].(map[string]any); ok {
54							tokens, _ = raw["total_tokens"].(float64)
55						}
56					}
57				}
58				// Tool calls from response
59				toolCalls, _ := data["tool_calls"].([]any)
60				finishReason, _ := data["finish_reason"].(string)
61				suffix := ""
62				if len(toolCalls) > 0 {
63					var names []string
64					for _, tc := range toolCalls {
65						if tcm, ok := tc.(map[string]any); ok {
66							n, _ := tcm["name"].(string)
67							if n != "" {
68								names = append(names, n)
69							}
70						}
71					}
72					suffix = fmt.Sprintf(" → %s", strings.Join(names, ", "))
73				} else if finishReason != "" {
74					suffix = fmt.Sprintf(" (%s)", finishReason)
75				}
76				fmt.Fprintf(&sb, "  ← llm response (%.0f tokens, %.1fs) %s%s\n", tokens, latency/1000, model, suffix)
77			case "llm.delta":
78				// Skip deltas — too verbose for summary
79			case "tool.call":
80				data, _ := entry["data"].(map[string]any)
81				name, _ := data["tool"].(string)
82				inp, _ := data["input"].(map[string]any)
83				dur, _ := data["duration_ms"].(float64)
84				argHint := ""
85				if len(inp) > 0 {
86					// Prefer path/command/query keys for display
87					for _, key := range []string{"path", "command", "query", "file"} {
88						if v, ok := inp[key]; ok {
89							argHint = truncateStr(fmt.Sprintf("%v", v), 60)
90							break
91						}
92					}
93					if argHint == "" {
94						for _, v := range inp {
95							argHint = truncateStr(fmt.Sprintf("%v", v), 60)
96							break
97						}
98					}
99				}
100				errMsg, _ := data["error"].(string)
101				errSuffix := ""
102				if errMsg != "" {
103					errSuffix = fmt.Sprintf(" ❌ %s", truncateStr(errMsg, 40))
104				}
105				durSuffix := ""
106				if dur > 0 {
107					durSuffix = fmt.Sprintf(" (%.1fs)", dur/1000)
108				}
109				fmt.Fprintf(&sb, "  🔧 %s %s%s%s\n", name, argHint, durSuffix, errSuffix)
110			case "bead.claimed":
111				data, _ := entry["data"].(map[string]any)
112				beadID, _ := data["bead_id"].(string)
113				title, _ := data["title"].(string)
114				if title != "" {
115					fmt.Fprintf(&sb, "\n▶ %s: %s\n", beadID, title)
116				} else {
117					fmt.Fprintf(&sb, "\n▶ %s\n", beadID)
118				}
119			case "bead.result":
120				data, _ := entry["data"].(map[string]any)
121				beadID, _ := data["bead_id"].(string)
122				status, _ := data["status"].(string)
123				detail, _ := data["detail"].(string)
124				resultRev, _ := data["result_rev"].(string)
125				preserveRef, _ := data["preserve_ref"].(string)
126				rationale, _ := data["no_changes_rationale"].(string)
127				durationMs, _ := data["duration_ms"].(float64)
128				var outcome string
129				switch status {
130				case "success":
131					shortRev := resultRev
132					if len(shortRev) > 8 {
133						shortRev = shortRev[:8]
134					}
135					if shortRev != "" {
136						outcome = fmt.Sprintf("merged (%s)", shortRev)
137					} else {
138						outcome = "merged"
139					}
140				case "already_satisfied", "no_changes":
141					outcome = status
142				default:
143					if detail == "" {
144						detail = status
145					}
146					if preserveRef != "" {
147						outcome = fmt.Sprintf("preserved: %s", detail)
148					} else {
149						outcome = fmt.Sprintf("error: %s", detail)
150					}
151				}
152				durStr := ""
153				if durationMs > 0 {
154					durStr = fmt.Sprintf(" (%.1fs)", durationMs/1000)
155				}
156				fmt.Fprintf(&sb, "✓ %s → %s%s\n", beadID, outcome, durStr)
157				if rationale != "" {
158					fmt.Fprintf(&sb, "  rationale: %s\n", rationale)
159				}
160			case "loop.end":
161				data, _ := entry["data"].(map[string]any)
162				attempts, _ := data["attempts"].(float64)
163				successes, _ := data["successes"].(float64)
164				failures, _ := data["failures"].(float64)
165				if attempts > 0 {
166					fmt.Fprintf(&sb, "\nloop done: %.0f attempted, %.0f succeeded, %.0f failed\n", attempts, successes, failures)
167				}
168			case "compaction.start":
169				// Suppress: we'll show a single line on compaction.end only if it succeeded.
170			case "compaction.end":
171				data, _ := entry["data"].(map[string]any)
172				success, _ := data["success"].(bool)
173				if success {
174					tokensBefore, _ := data["tokens_before"].(float64)
175					tokensAfter, _ := data["tokens_after"].(float64)
176					if tokensBefore > 0 && tokensAfter > 0 {
177						fmt.Fprintf(&sb, "  ⚡ compacted context (%.0f → %.0f tokens)\n", tokensBefore, tokensAfter)
178					} else {
179						fmt.Fprintf(&sb, "  ⚡ compacted context\n")
180					}
181				}
182			}
183		}
184		return sb.String()
185	}
186	
187	func truncateStr(s string, maxLen int) string {
188		if len(s) <= maxLen {
189			return s
190		}
191		return s[:maxLen-1] + "…"
192	}
