18	// claudeStreamEvent is a minimal, lenient view of a claude CLI stream-json
19	// event. Only the fields we need for progress and final result are decoded.
20	type claudeStreamEvent struct {
21		Type    string          `json:"type"`
22		Subtype string          `json:"subtype"`
23		Message json.RawMessage `json:"message"`
24		Result  string          `json:"result"`
25	
26		// result-event fields
27		Usage struct {
28			InputTokens         int `json:"input_tokens"`
29			OutputTokens        int `json:"output_tokens"`
30			CacheCreationTokens int `json:"cache_creation_input_tokens"`
31			CacheReadTokens     int `json:"cache_read_input_tokens"`
32		} `json:"usage"`
33		TotalCostUSD    float64 `json:"total_cost_usd"`
34		DurationMsField int64   `json:"duration_ms"`
35		SessionID       string  `json:"session_id"`
36		IsError         bool    `json:"is_error"`
37	
38		// system/init fields
39		Model string `json:"model"`
40	}
41	
42	// claudeAssistantMessage is the shape of the "message" field in an
43	// {"type":"assistant",...} stream-json event. It is Claude's native
44	// Messages API payload.
45	type claudeAssistantMessage struct {
46		ID      string               `json:"id"`
47		Model   string               `json:"model"`
48		Content []claudeMessageBlock `json:"content"`
49		Usage   claudeAssistantUsage `json:"usage"`
50		Stop    string               `json:"stop_reason,omitempty"`
51	}
52	
53	type claudeMessageBlock struct {
54		Type  string          `json:"type"`
55		Text  string          `json:"text,omitempty"`
56		ID    string          `json:"id,omitempty"`
57		Name  string          `json:"name,omitempty"`
58		Input json.RawMessage `json:"input,omitempty"`
59	}
60	
61	type claudeAssistantUsage struct {
62		InputTokens  int `json:"input_tokens"`
63		OutputTokens int `json:"output_tokens"`
64	}
65	
66	// claudeStreamResult is the aggregated final state from parsing a
67	// claude stream-json output.
68	type claudeStreamResult struct {
69		FinalText    string
70		SessionID    string
71		Model        string
72		InputTokens  int
73		OutputTokens int
74		CostUSD      float64
75		ToolCalls    int
76		TurnCount    int
77		IsError      bool
78	}
