80	// parseClaudeStream reads newline-delimited claude stream-json events from r,
81	// writes translated progress entries to progressLog (one JSONL line per tool
82	// call and a session.start event on init), and returns an aggregated
83	// claudeStreamResult covering token usage, final text, and counts.
84	//
85	// The progress entries use the same event type names the ddx-agent harness
86	// emits (session.start, tool.call, llm.response) so the existing
87	// TailSessionLogs / FormatSessionLogLines pipeline can render them as
88	// real-time progress without any changes.
89	//
90	// beadID and startTime are optional: when provided, each progress entry
91	// receives a data.bead_id and data.elapsed_ms field for cross-referencing.
92	//
93	// progressLog may be nil; if nil, progress entries are discarded but the
94	// aggregate result is still returned.
95	func parseClaudeStream(r io.Reader, progressLog io.Writer, sessionID, beadID string, startTime time.Time) (*claudeStreamResult, error) {
96		if startTime.IsZero() {
97			startTime = time.Now()
98		}
99		res := &claudeStreamResult{SessionID: sessionID}
100		scanner := bufio.NewScanner(r)
101		scanner.Buffer(make([]byte, 0, 256*1024), 16*1024*1024) // 16MB max line — claude can dump big tool results
102	
103		seq := 0
104		emit := func(evType, dataJSON string) {
105			if progressLog == nil {
106				return
107			}
108			entry := map[string]any{
109				"session_id": sessionID,
110				"seq":        seq,
111				"type":       evType,
112				"ts":         time.Now().UTC().Format(time.RFC3339Nano),
113				"data":       json.RawMessage(dataJSON),
114			}
115			seq++
116			line, err := json.Marshal(entry)
117			if err != nil {
118				return
119			}
120			_, _ = progressLog.Write(line)
121			_, _ = progressLog.Write([]byte("\n"))
122		}
123	
124		wroteStart := false
125		for scanner.Scan() {
126			line := strings.TrimSpace(scanner.Text())
127			if line == "" {
128				continue
129			}
130			var ev claudeStreamEvent
131			if err := json.Unmarshal([]byte(line), &ev); err != nil {
132				// Not a JSON event — skip silently to be lenient.
133				continue
134			}
135	
136			elapsedMS := time.Since(startTime).Milliseconds()
137			switch ev.Type {
138			case "system":
139				if ev.Subtype == "init" && !wroteStart {
140					wroteStart = true
141					if ev.Model != "" {
142						res.Model = ev.Model
143					}
144					if ev.SessionID != "" {
145						res.SessionID = ev.SessionID
146					}
147					data, _ := json.Marshal(map[string]any{
148						"model":      res.Model,
149						"session_id": res.SessionID,
150						"bead_id":    beadID,
151						"elapsed_ms": elapsedMS,
152						"harness":    "claude",
153					})
154					emit("session.start", string(data))
155				}
156	
157			case "assistant":
158				var msg claudeAssistantMessage
159				if len(ev.Message) > 0 {
160					_ = json.Unmarshal(ev.Message, &msg)
161				}
162				if msg.Model != "" && res.Model == "" {
163					res.Model = msg.Model
164				}
165				// Running usage totals so TailSessionLogs has the latest view.
166				if msg.Usage.InputTokens > 0 {
167					res.InputTokens = msg.Usage.InputTokens
168				}
169				if msg.Usage.OutputTokens > 0 {
170					res.OutputTokens = msg.Usage.OutputTokens
171				}
172	
173				// Count each assistant message as one turn for operator visibility.
174				res.TurnCount++
175	
176				// Collect tool-use names emitted in this turn, so we can translate
177				// the assistant event into an llm.response-like progress entry.
178				var toolNames []map[string]string
179				var textOut strings.Builder
180				for _, block := range msg.Content {
181					switch block.Type {
182					case "text":
183						if block.Text != "" {
184							if textOut.Len() > 0 {
185								textOut.WriteString("\n")
186							}
187							textOut.WriteString(block.Text)
188						}
189					case "tool_use":
190						name := block.Name
191						if name == "" {
192							name = "tool"
193						}
194						toolNames = append(toolNames, map[string]string{"name": name})
195					}
196				}
197	
198				data, _ := json.Marshal(map[string]any{
199					"model":         res.Model,
200					"latency_ms":    elapsedMS,
201					"tool_calls":    toolNames,
202					"turn":          res.TurnCount,
203					"bead_id":       beadID,
204					"elapsed_ms":    elapsedMS,
205					"input_tokens":  res.InputTokens,
206					"output_tokens": res.OutputTokens,
207					"attempt": map[string]any{
208						"cost": map[string]any{
209							"raw": map[string]any{
210								"total_tokens": res.InputTokens + res.OutputTokens,
211							},
212						},
213					},
214				})
215				emit("llm.response", string(data))
216	
217				// Emit a tool.call entry for each tool_use block so progress
218				// output shows per-tool lines (matches ddx-agent format).
219				for _, block := range msg.Content {
220					if block.Type != "tool_use" {
221						continue
222					}
223					res.ToolCalls++
224					input := map[string]any{}
225					if len(block.Input) > 0 {
226						_ = json.Unmarshal(block.Input, &input)
227					}
228					toolData, _ := json.Marshal(map[string]any{
229						"tool":       block.Name,
230						"input":      input,
231						"bead_id":    beadID,
232						"elapsed_ms": elapsedMS,
233						"turn":       res.TurnCount,
234					})
235					emit("tool.call", string(toolData))
236				}
237	
238				// Save the most recent text content so, if the final result
239				// event is missing or truncated, we can still return the
240				// agent's last spoken text.
241				if t := textOut.String(); t != "" {
242					res.FinalText = t
243				}
244	
245			case "user":
246				// user events carry tool_result content. Not useful for progress,
247				// already captured by the tool.call timing above.
248	
249			case "result":
250				// Final event. Extract authoritative usage/cost/result text.
251				if ev.Result != "" {
252					res.FinalText = ev.Result
253				}
254				if ev.Usage.InputTokens > 0 {
255					res.InputTokens = ev.Usage.InputTokens
256				}
257				if ev.Usage.OutputTokens > 0 {
258					res.OutputTokens = ev.Usage.OutputTokens
259				}
260				if ev.TotalCostUSD > 0 {
261					res.CostUSD = ev.TotalCostUSD
262				}
263				if ev.SessionID != "" {
264					res.SessionID = ev.SessionID
265				}
266				if ev.IsError {
267					res.IsError = true
268				}
269			}
270		}
271		if err := scanner.Err(); err != nil && !errors.Is(err, io.EOF) {
272			return res, err
273		}
274		return res, nil
275	}
