277	// resolveClaudeProgressLogDir picks the directory for the per-run claude
278	// progress JSONL trace. The per-run override (opts.SessionLogDir) takes
279	// precedence over the runner-wide Config.SessionLogDir so managed
280	// execute-bead invocations can redirect the trace into the DDx-owned
281	// execution bundle's embedded/ dir instead of the runner's default
282	// .ddx/agent-logs. Matches the agent_runner.go precedence pattern so the
283	// two harnesses behave identically under execute-bead.
284	func resolveClaudeProgressLogDir(opts RunArgs, cfg Config) string {
285		if opts.SessionLogDir != "" {
286			return opts.SessionLogDir
287		}
288		return cfg.SessionLogDir
289	}
