291	// runClaudeStreaming is the streaming execution path for the claude harness.
292	// It launches the claude binary directly (bypassing the standard Executor
293	// abstraction so it can pipe stdout line-by-line), parses stream-json events
294	// as they arrive, and writes per-tool progress entries to a ddx-agent-style
295	// JSONL file in opts.SessionLogDir (when set) or r.Config.SessionLogDir so
296	// `ddx server workers log` sees real-time activity.
297	//
298	// On success it returns a *Result shaped exactly like the non-streaming
299	// path, so callers downstream (processResult, session logging) are unchanged.
300	//
301	// If the claude CLI rejects the stream-json flags (older build, unsupported
302	// option), the caller falls back to the non-streaming path via
303	// runClaudeWithFallbackFn.
304	func runClaudeStreamingFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
305		args := BuildArgs(harness, buildArgsInputFromRunArgs(resolvedOpts), model)
306	
307		start := time.Now()
308		runCtx, cancel := context.WithCancel(ctx)
309		defer cancel()
310	
311		cmd := osexec.CommandContext(runCtx, harness.Binary, args...)
312		if execDir != "" {
313			cmd.Dir = execDir
314		}
315		if harness.PromptMode == "stdin" {
316			cmd.Stdin = strings.NewReader(prompt)
317		}
318	
319		stdoutPipe, err := cmd.StdoutPipe()
320		if err != nil {
321			return nil, err
322		}
323		stderrPipe, err := cmd.StderrPipe()
324		if err != nil {
325			return nil, err
326		}
327	
328		if err := cmd.Start(); err != nil {
329			return nil, err
330		}
331	
332		// Open the progress log file. Using agent-<sessionID>.jsonl so
333		// TailSessionLogs (which only reads files matching "agent-*.jsonl")
334		// picks the stream up automatically.
335		sessionID := fmt.Sprintf("claude-%d", time.Now().UnixNano())
336		beadID := ""
337		if resolvedOpts.Correlation != nil {
338			beadID = resolvedOpts.Correlation["bead_id"]
339		}
340		var progressLog *os.File
341		progressLogDir := resolveClaudeProgressLogDir(resolvedOpts, r.Config)
342		if progressLogDir != "" {
343			if err := os.MkdirAll(progressLogDir, 0o755); err == nil {
344				logPath := filepath.Join(progressLogDir, "agent-"+sessionID+".jsonl")
345				if f, err := os.OpenFile(logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644); err == nil {
346					progressLog = f
347					defer progressLog.Close()
348				}
349			}
350		}
351	
352		// Stream stdout: parse events as they arrive and mirror raw bytes into
353		// a buffer so we can return the full output for session logging.
354		var rawOut strings.Builder
355		stdoutReader, stdoutWriter := io.Pipe()
356		var parseResult *claudeStreamResult
357		var parseErr error
358		var parseWG sync.WaitGroup
359		parseWG.Add(1)
360		go func() {
361			defer parseWG.Done()
362			parseResult, parseErr = parseClaudeStream(stdoutReader, progressLog, sessionID, beadID, start)
363		}()
364	
365		// Tee stdout into rawOut (for the final Result.Output) and the parser.
366		stdoutDone := make(chan struct{})
367		go func() {
368			defer close(stdoutDone)
369			// Pipe bytes through a tee so both the raw buffer and the parser see them.
370			tee := io.TeeReader(stdoutPipe, &stringWriter{&rawOut})
371			_, _ = io.Copy(stdoutWriter, tee)
372			_ = stdoutWriter.Close()
373		}()
374	
375		var stderrBuf strings.Builder
376		stderrDone := make(chan struct{})
377		go func() {
378			defer close(stderrDone)
379			_, _ = io.Copy(&stringWriter{&stderrBuf}, stderrPipe)
380		}()
381	
382		// Idle-timeout watchdog: if no stdout progress for `timeout` duration,
383		// cancel the context. The tee+parse goroutines handle activity naturally
384		// via the pipe; for simplicity we use an overall deadline here. The
385		// existing stream-json output is frequent enough that a long per-bead
386		// deadline is the right behavior for operators.
387		var timedOut bool
388		if timeout > 0 {
389			stop := make(chan struct{})
390			go func() {
391				select {
392				case <-stop:
393				case <-time.After(timeout):
394					timedOut = true
395					cancel()
396				}
397			}()
398			defer close(stop)
399		}
400	
401		<-stdoutDone
402		<-stderrDone
403		parseWG.Wait()
404		runErr := cmd.Wait()
405		elapsed := time.Since(start)
406	
407		exitCode := 0
408		if runErr != nil {
409			if exitErr, ok := runErr.(*osexec.ExitError); ok {
410				exitCode = exitErr.ExitCode()
411			} else if errors.Is(runCtx.Err(), context.DeadlineExceeded) || timedOut {
412				exitCode = -1
413			} else {
414				exitCode = -1
415			}
416		}
417	
418		execResult := &ExecResult{
419			Stdout:   rawOut.String(),
420			Stderr:   stderrBuf.String(),
421			ExitCode: exitCode,
422		}
423	
424		var execErr error
425		if timedOut {
426			execErr = context.DeadlineExceeded
427		} else if runErr != nil && exitCode == 0 {
428			execErr = runErr
429		}
